// Включить валидацию
export function enableValidation(input) {
  const arrInputText = Array.from(
    document.querySelectorAll(`${input.popupForm} .popup__input`)
  );

  arrInputText.forEach((item) => {
    item.addEventListener("input", (evt) => {
      const activeForm = evt.target.closest(`.popup__form`);
      const arrInputActiveForm = Array.from(
        activeForm.querySelectorAll(".popup__input")
      );

      checkValidateDefault(arrInputActiveForm, evt.target);
    });
  });
}

