// проверка на валидность default
function checkValidateDefault(arrInputActiveForm, evtTarget) {
  if (
    arrInputActiveForm.every((elmValid) => {
      return elmValid.validity.valid === true;
    })
  ) {
    clearError(evtTarget);
    console.log(evtTarget.validity.valid);
  } else {
    console.log(evtTarget.validity.valid);
    showError(evtTarget);
  }
}



// очистить ошибку
function clearError(elementEvt) {
  document.querySelector(`#${elementEvt.id}__error_message`).textContent = "";
  activeBtnSubmit(elementEvt.closest(".popup__form"));
}

// очистка "предыдущей" валидации
export function clearValidation(form) {
  Array.from(form.querySelectorAll(".popup__input")).forEach((item) => {
    document.querySelector(`#${item.id}__error_message`).textContent = "";
  });
  inactiveBtnSubmit(form);
}

// сделать кнопку активной
function activeBtnSubmit(form) {
  form.querySelector(".popup__button").removeAttribute("style");
  form.querySelector(".popup__button").removeAttribute("disabled");
}

// сделать кнопку неактивной
function inactiveBtnSubmit(form) {
  form.querySelector(".popup__button").setAttribute("disabled", "");
  form
    .querySelector(".popup__button")
    .setAttribute(
      "style",
      "background: none; color: rgba(0, 0, 0, 0.3); border: solid 1px rgba(0, 0, 0, 0.3)"
    );
}
